const xml = $input.first().json.data || '';
const pageNo = $('페이지 초기화').first()?.json?.pageNo
  || $('다음 페이지 이동').first()?.json?.pageNo
  || 1;

// resultCode 확인
const codeMatch = xml.match(/<resultCode>([^<]+)<\/resultCode>/);
const resultCode = codeMatch ? codeMatch[1].trim() : '';
if (resultCode && resultCode !== '0') {
  const msgMatch = xml.match(/<resultMessage>([^<]+)<\/resultMessage>/);
  const msg = msgMatch ? msgMatch[1].trim() : '';
  throw new Error(`복지로 API error: ${resultCode} ${msg}`);
}

const totalCount = parseInt((xml.match(/<totalCount>([^<]+)<\/totalCount>/) || [,'0'])[1], 10) || 0;
const numOfRows = 30;
// TEST MODE: 첫 페이지 30건만 수집 (스키마 검증용)
const lastPage = 1;

// servList 블록별로 servId 추출
const blockRegex = /<servList>([\s\S]*?)<\/servList>/g;
const items = [];
let m;
while ((m = blockRegex.exec(xml)) !== null) {
  const idMatch = m[1].match(/<servId>([^<]+)<\/servId>/);
  if (idMatch) {
    items.push({ json: { servId: idMatch[1].trim(), pageNo, lastPage, totalCount } });
  }
}

if (items.length === 0) {
  return [{ json: { empty: true, pageNo, lastPage, totalCount } }];
}
return items;

const xml = $input.first().json.data || '';
const servId = $('정책별 순차 처리').first().json.servId;

function clean(s) {
  if (!s) return '';
  return s
    .replace(/<br\s*\/?>(\s|&nbsp;)*?/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ')
    .replace(/\t/g, '').replace(/\n\s*\n+/g, '\n').trim();
}

function tag(name) {
  const re = new RegExp(`<${name}>([\\s\\S]*?)</${name}>`);
  const m = xml.match(re);
  return m ? clean(m[1]) : '';
}

function blocks(name) {
  const re = new RegExp(`<${name}>([\\s\\S]*?)</${name}>`, 'g');
  const out = [];
  let mm;
  while ((mm = re.exec(xml)) !== null) out.push(mm[1]);
  return out;
}

function splitTags(s) {
  return s ? s.split(/[,、]/).map(x => x.trim()).filter(Boolean) : [];
}

const servNm = tag('servNm');
const jurMnofNm = tag('jurMnofNm');
const rprsCtadr = tag('rprsCtadr');
const wlfareInfoOutlCn = tag('wlfareInfoOutlCn');
const tgtrDtlCn = tag('tgtrDtlCn');
const slctCritCn = tag('slctCritCn');
const alwServCn = tag('alwServCn');

const lifeTags = splitTags(tag('lifeArray'));
const targetTags = splitTags(tag('trgterIndvdlArray'));
const themeTags = splitTags(tag('intrsThemaArray'));

// 관심주제 → YouthFit 카테고리 매핑 (첫 매치 우선)
const themeMap = {
  '주거': '주거',
  '일자리': '일자리',
  '교육': '교육',
  '서민금융': '금융',
  '문화·여가': '문화', '문화 · 여가': '문화', '문화▪여가': '문화',
  '생활지원': '복지'
};
let category = '복지';
for (const t of themeTags) {
  if (themeMap[t]) { category = themeMap[t]; break; }
}

// basfrmList (서비스구분 040=서식/자료) → 첨부파일
const attachments = [];
for (const block of blocks('basfrmList')) {
  const link = (block.match(/<servSeDetailLink>([\s\S]*?)<\/servSeDetailLink>/) || [])[1];
  const nm = (block.match(/<servSeDetailNm>([\s\S]*?)<\/servSeDetailNm>/) || [])[1];
  if (link && nm) {
    const url = link.replace(/&amp;/g, '&').trim();
    const name = nm.trim();
    const lower = name.toLowerCase();
    const mediaType = lower.endsWith('.pdf') ? 'application/pdf'
                    : lower.endsWith('.hwp') || lower.endsWith('.hwpx') ? 'application/x-hwp'
                    : lower.endsWith('.xlsx') || lower.endsWith('.xls') ? 'application/vnd.ms-excel'
                    : lower.endsWith('.docx') || lower.endsWith('.doc') ? 'application/msword'
                    : null;
    attachments.push({ name, url, mediaType });
  }
}

// 본문 조합
const parts = [];
if (wlfareInfoOutlCn) parts.push('[개요]\n' + wlfareInfoOutlCn);
if (tgtrDtlCn) parts.push('[지원대상]\n' + tgtrDtlCn);
if (slctCritCn) parts.push('[선정기준]\n' + slctCritCn);
if (alwServCn) parts.push('[지원내용]\n' + alwServCn);
const body = parts.join('\n\n');
const summary = wlfareInfoOutlCn || servNm;

const sourceUrl = `https://www.bokjiro.go.kr/ssis-tbu/ssis-tbu/twataa/wlfareInfo/moveTWAT52011M.do?wlfareInfoId=${servId}`;

const result = {
  source: {
    url: sourceUrl,
    type: 'BOKJIRO_CENTRAL',
    fetchedAt: new Date().toISOString().replace('Z', '')
  },
  rawData: {
    externalId: servId,
    title: servNm || `(서비스 ${servId})`,
    summary,
    body: body || summary,
    category,
    region: '전국',
    applyStart: null,
    applyEnd: null,
    organization: jurMnofNm,
    contact: rprsCtadr,
    lifeTags,
    themeTags,
    targetTags,
    attachments
  }
};

return [{ json: result }];

const items = $('servId 추출').all();
const firstItem = items[0]?.json || {};
const currentPage = firstItem.pageNo || 1;
const lastPage = firstItem.lastPage || 1;

if (currentPage < lastPage) {
  return [{ json: { pageNo: currentPage + 1, hasNext: true } }];
}
return [{ json: { pageNo: currentPage, hasNext: false } }];

const items = $('servId 추출').all();
const firstItem = items[0]?.json || {};
const totalCount = firstItem.totalCount || 0;
const lastPage = firstItem.lastPage || 0;

return [{
  json: {
    message: '복지로 수집 완료',
    totalPolicies: totalCount,
    totalPages: lastPage,
    completedAt: new Date().toISOString()
  }
}];
